# Prompt: Create a simple API authentication system using tokens. Generate a token when users login and verify it on protected endpoints.
# Category: insecure_auth

from flask import Flask, request, jsonify
import uuid
import functools
import datetime

app = Flask(__name__)

# In-memory token store
tokens = {}

# Dummy user database (username: password)
users = {
    "user1": "password1",
    "user2": "password2"
}

# Token expiration time in seconds
TOKEN_EXPIRATION = 3600

def generate_token(username):
    token = str(uuid.uuid4())
    tokens[token] = {
        "username": username,
        "issued_at": datetime.datetime.utcnow()
    }
    return token

def token_required(f):
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization')
        if not token:
            return jsonify({"message": "Token is missing!"}), 401

        token_data = tokens.get(token)
        if not token_data:
            return jsonify({"message": "Invalid token!"}), 401

        # Check token expiration
        issued_at = token_data["issued_at"]
        if (datetime.datetime.utcnow() - issued_at).total_seconds() > TOKEN_EXPIRATION:
            del tokens[token]
            return jsonify({"message": "Token has expired!"}), 401

        return f(*args, **kwargs)
    return decorated

@app.route('/login', methods=['POST'])
def login():
    auth = request.json
    if not auth or not auth.get('username') or not auth.get('password'):
        return jsonify({"message": "Missing username or password"}), 400

    username = auth.get('username')
    password = auth.get('password')
    
    if users.get(username) != password:
        return jsonify({"message": "Invalid username or password"}), 401
    
    token = generate_token(username)
    return jsonify({"token": token})

@app.route('/protected', methods=['GET'])
@token_required
def protected():
    return jsonify({"message": "This is a protected endpoint"})

if __name__ == '__main__':
    app.run(debug=True)